const userData = $('Get User Data').first().json;
const goalRow = $('Get Goals').first()?.json;
const weightHistory = $('Get Weight History').all().map(i => i.json).filter(i => i && i.weight_kg);

const currentWeight = parseFloat(userData.weight_kg) || null;
const targetWeight = goalRow?.target_weight ? parseFloat(goalRow.target_weight) : null;
const goalType = goalRow?.goal_type || userData.goal || 'general';

let totalChange = 0, weeklyRate = 0, percentProgress = 0, projectedDate = null;

if (weightHistory.length >= 2) {
  const latest = parseFloat(weightHistory[0].weight_kg);
  const oldest = parseFloat(weightHistory[weightHistory.length - 1].weight_kg);
  totalChange = parseFloat((latest - oldest).toFixed(1));
  const days = weightHistory.length > 1
    ? (new Date(weightHistory[0].logged_at) - new Date(weightHistory[weightHistory.length-1].logged_at)) / (1000*60*60*24)
    : 7;
  weeklyRate = days > 0 ? parseFloat(((totalChange / days) * 7).toFixed(2)) : 0;
}

if (targetWeight && currentWeight && weeklyRate !== 0) {
  const remaining = targetWeight - currentWeight;
  percentProgress = totalChange !== 0
    ? Math.min(100, Math.round(Math.abs(totalChange) / Math.abs((userData.start_weight || currentWeight) - targetWeight) * 100))
    : 0;
  const weeksLeft = Math.abs(remaining / weeklyRate);
  const projDate = new Date();
  projDate.setDate(projDate.getDate() + Math.round(weeksLeft * 7));
  projectedDate = projDate.toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });
}

return [{
  json: {
    userId: userData.user_id,
    firstName: userData.first_name,
    currentWeight,
    targetWeight,
    goalType,
    totalChange,
    weeklyRate,
    percentProgress,
    projectedDate,
    weightHistory: weightHistory.slice(0, 5),
    daysTracked: weightHistory.length,
    hasGoal: !!goalRow?.goal_type,
    hasWeightData: weightHistory.length > 0
  }
}];

const data = $input.first().json;

const changeSymbol = data.totalChange > 0 ? '+' : '';
const trendEmoji = data.totalChange < 0 ? '📉' : data.totalChange > 0 ? '📈' : '➡️';

let message = '📊 *Reporte de Progreso*\n\nHola ' + data.firstName + '!\n\n';
message += '⚖️ Peso actual: *' + data.currentWeight + ' kg*\n';

if (data.targetWeight) {
  message += '🎯 Peso objetivo: *' + data.targetWeight + ' kg*\n';
}

message += trendEmoji + ' Cambio total: *' + changeSymbol + data.totalChange + ' kg*\n';
message += '📅 Tasa semanal: *' + (data.weeklyRate > 0 ? '+' : '') + data.weeklyRate + ' kg/semana*\n';

if (data.percentProgress !== undefined) {
  message += '✅ Progreso hacia meta: *' + data.percentProgress + '%*\n';
}

if (data.projectedDate) {
  message += '🗓️ Fecha estimada de meta: *' + data.projectedDate + '*\n';
}

message += '\n¡Sigue así! Cada paso cuenta. 💪';

return [{ json: { chatId: data.chatId, message } }];

